	@Test
	void mergeJoinRulePreservesResultsRandomized() {
		MergeJoinRule rule = new MergeJoinRule();
		int modified = 0;

		for (int seed = 1; seed <= 20; seed++) {
			OrderedListTripleSource tripleSource = new OrderedListTripleSource(generateRandomStatements(seed));
			EvaluationStatistics statistics = new EvaluationStatistics();
			JoinOptimizationContext context = context(tripleSource, statistics);
			Random random = new Random(seed * 17L + 3L);
			String query = randomInnerJoinQuery(random, 3 + random.nextInt(2));

			TupleExpr original = parseQuery(query);
			TupleExpr rewritten = parseQuery(query);
			Map<String, String> diagnostics = new HashMap<>();
			if (rule.apply(rewritten, context, diagnostics)) {
				modified++;
			}

			List<BindingSet> baseline = evaluate(original, tripleSource, statistics);
			List<BindingSet> candidate = evaluate(rewritten, tripleSource, statistics);
			assertThat(asCounts(candidate)).as("seed=%s query=%s", seed, query).isEqualTo(asCounts(baseline));
		}

		assertThat(modified).isGreaterThan(0);
	}

