	private TupleExpr parseQuery(String query) {
		ParsedTupleQuery parsedQuery = QueryParserUtil.parseTupleQuery(QueryLanguage.SPARQL, query, null);
		return parsedQuery.getTupleExpr().clone();
	}

	private JoinOptimizationContext context(OrderedListTripleSource tripleSource, EvaluationStatistics statistics) {
		return context(tripleSource, statistics, new DefaultUncertaintyAwareEstimator());
	}

	private JoinOptimizationContext context(OrderedListTripleSource tripleSource, EvaluationStatistics statistics,
			UncertaintyAwareEstimator estimator) {
		JoinEngineConfig defaults = JoinEngineConfig.defaults();
		JoinEngineConfig config = new JoinEngineConfig(true, defaults.getRiskPenaltyWeight(), defaults.getDpThreshold(),
				Math.max(3, defaults.getPortfolioSize()), defaults.isEnableDp());
		return new JoinOptimizationContext(statistics, tripleSource, null, EmptyBindingSet.getInstance(), Set.of(),
				config, OptimizationTraceSink.NOOP, BanditPolicy.noop(), estimator, new DefaultCostModel());
	}

	private Join firstJoin(TupleExpr expr) {
		AtomicReference<Join> found = new AtomicReference<>();
		expr.visit(new AbstractSimpleQueryModelVisitor<RuntimeException>(true) {
			@Override
			public void meet(Join node) {
				found.compareAndSet(null, node);
				super.meet(node);
			}
		});
		Join join = found.get();
		if (join == null) {
			throw new IllegalStateException("Expected at least one join: " + expr.getSignature());
		}
		return join;
	}

	private Join firstStatementPairJoin(TupleExpr expr) {
		AtomicReference<Join> found = new AtomicReference<>();
		expr.visit(new AbstractSimpleQueryModelVisitor<RuntimeException>(true) {
			@Override
			public void meet(Join node) {
				if (found.get() == null && node.getLeftArg() instanceof StatementPattern
						&& node.getRightArg() instanceof StatementPattern) {
					found.set(node);
				}
				super.meet(node);
			}
		});
		Join join = found.get();
		if (join == null) {
			throw new IllegalStateException("Expected statement-pattern join: " + expr.getSignature());
		}
		return join;
	}

	private List<BindingSet> evaluate(TupleExpr expr, TripleSource tripleSource, EvaluationStatistics statistics) {
		DefaultEvaluationStrategy strategy = new DefaultEvaluationStrategy(tripleSource, null, null, 0L, statistics);
		try (CloseableIteration<BindingSet> results = strategy.precompile(expr)
				.evaluate(EmptyBindingSet.getInstance())) {
			List<BindingSet> collected = new ArrayList<>();
			while (results.hasNext()) {
				collected.add(new QueryBindingSet(results.next()));
			}
			return collected;
		}
	}

	private Map<BindingSet, Long> asCounts(List<BindingSet> results) {
		Map<BindingSet, Long> counts = new HashMap<>();
		for (BindingSet result : results) {
			counts.merge(new QueryBindingSet(result), 1L, Long::sum);
		}
		return counts;
	}

	private List<Statement> generateRandomStatements(long seed) {
		Random random = new Random(seed);
		Set<Statement> statements = new LinkedHashSet<>();
		while (statements.size() < RANDOM_TRIPLE_COUNT) {
			IRI subject = VF.createIRI("urn:n" + random.nextInt(RANDOM_SUBJECT_POOL_SIZE));
			IRI predicate = VF.createIRI("urn:p" + random.nextInt(RANDOM_PREDICATE_POOL_SIZE));
			IRI object = VF.createIRI("urn:n" + random.nextInt(RANDOM_SUBJECT_POOL_SIZE));
			statements.add(VF.createStatement(subject, predicate, object));
		}
		return List.copyOf(statements);
	}

	private String randomInnerJoinQuery(Random random, int patternCount) {
		StringBuilder builder = new StringBuilder("SELECT * WHERE { ");
		String anchorVar = "?v0";
		String previousVar = anchorVar;

		for (int i = 0; i < patternCount; i++) {
			String subject = i == 0 ? anchorVar : (random.nextBoolean() ? previousVar : anchorVar);
			String objectVar = "?v" + (i + 1);
			String object = random.nextDouble() < 0.25d ? randomNodeIri(random) : objectVar;
			String predicate = "<urn:p" + random.nextInt(RANDOM_PREDICATE_POOL_SIZE) + ">";

			builder.append(subject)
					.append(' ')
					.append(predicate)
					.append(' ')
					.append(object)
					.append(" . ");

			if (object.startsWith("?")) {
				previousVar = object;
			}
		}

		builder.append('}');
		return builder.toString();
	}

	private String randomNodeIri(Random random) {
		return "<urn:n" + random.nextInt(RANDOM_SUBJECT_POOL_SIZE) + ">";
	}

	private static final class OrderedListTripleSource implements TripleSource {

		private static final Set<StatementOrder> ORDER_SUPPORT = Set.of(
				StatementOrder.S,
				StatementOrder.P,
				StatementOrder.O,
				StatementOrder.C);

		private final List<Statement> statements;
		private final Comparator<Value> valueComparator = Comparator
				.nullsFirst(Comparator.comparing(Value::stringValue));

		private OrderedListTripleSource(List<Statement> statements) {
			this.statements = List.copyOf(statements);
		}

		@Override
		public CloseableIteration<? extends Statement> getStatements(Resource subj, IRI pred, Value obj,
				Resource... contexts) {
			return new CloseableIteratorIteration<>(filter(subj, pred, obj, contexts).iterator());
		}

		@Override
		public CloseableIteration<? extends Statement> getStatements(StatementOrder order, Resource subj, IRI pred,
				Value obj,
				Resource... contexts) {
			List<Statement> filtered = filter(subj, pred, obj, contexts);
			filtered.sort(order.getComparator(valueComparator));
			return new CloseableIteratorIteration<>(filtered.iterator());
		}

		@Override
		public Set<StatementOrder> getSupportedOrders(Resource subj, IRI pred, Value obj, Resource... contexts) {
			return ORDER_SUPPORT;
		}

		@Override
		public Comparator<Value> getComparator() {
			return valueComparator;
		}

		@Override
		public ValueFactory getValueFactory() {
			return VF;
		}

		private List<Statement> filter(Resource subj, IRI pred, Value obj, Resource... contexts) {
			List<Statement> matches = new ArrayList<>();
			boolean hasContexts = contexts != null && contexts.length > 0;
			for (Statement statement : statements) {
				if (subj != null && !subj.equals(statement.getSubject())) {
					continue;
				}
				if (pred != null && !pred.equals(statement.getPredicate())) {
					continue;
				}
				if (obj != null && !obj.equals(statement.getObject())) {
					continue;
				}
				if (hasContexts && !matchesContext(statement, contexts)) {
					continue;
				}
				matches.add(statement);
			}
			return matches;
		}

		private boolean matchesContext(Statement statement, Resource[] contexts) {
			for (Resource context : contexts) {
				if (Objects.equals(context, statement.getContext())) {
					return true;
				}
			}
			return false;
		}
	}

	private static final class PredicateRowsEstimator implements UncertaintyAwareEstimator {

		private final Map<String, Double> rowsByPredicate;

		private PredicateRowsEstimator(Map<String, Double> rowsByPredicate) {
			this.rowsByPredicate = rowsByPredicate;
		}

		@Override
		public Estimate estimateRows(TupleExpr expr, JoinOptimizationContext ctx) {
			if (expr instanceof StatementPattern) {
				StatementPattern pattern = (StatementPattern) expr;
				Var predicate = pattern.getPredicateVar();
				if (predicate != null && predicate.hasValue()) {
					double rows = rowsByPredicate.getOrDefault(predicate.getValue().stringValue(), 1.0d);
					return new Estimate(rows, 0.25d, "TEST", Map.of());
				}
			}
			return new Estimate(1.0d, 0.25d, "TEST", Map.of());
		}
	}
